powershell.exe -NoProfile -Command "
Get-ChildItem 'C:\Program Files\Docker' -Recurse -Filter 'docker.exe' -ErrorAction SilentlyContinue | Select-Object -First 5 | ForEach-Object { Write-Host \$_.FullName }
" 2>&1
